func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
	// Create a copy of the grid to avoid modifying the original
	result := make([][]int64, len(grid))
	for i := range grid {
		result[i] = make([]int64, len(grid[i]))
		copy(result[i], grid[i])
	}

	// Extract the submatrix
	submatrix := make([][]int64, k)
	for i := 0; i < k; i++ {
		submatrix[i] = make([]int64, k)
		for j := 0; j < k; j++ {
			submatrix[i][j] = result[int(x)+i][int(y)+j]
		}
	}

	// Reverse the submatrix
	reversedSubmatrix := make([][]int64, k)
	for i := 0; i < k; i++ {
		reversedSubmatrix[i] = make([]int64, k)
		for j := 0; j < k; j++ {
			reversedSubmatrix[i][j] = submatrix[k-1-i][j]
		}
	}

	// Put the reversed submatrix back into the result
	for i := 0; i < k; i++ {
		for j := 0; j < k; j++ {
			result[int(x)+i][int(y)+j] = reversedSubmatrix[i][j]
		}
	}

	return result
}
